import './App.css';
import axios from 'axios';
import { useEffect, useState } from 'react';

function App() {
    const [listOfUsers, setListOfUsers] = useState([]);

    useEffect(() => {
        axios.get("http://localhost:3001/users").then((response) => {
            setListOfUsers(response.data);
        })
    }, []);

    const listUsers = listOfUsers.map((value, key) => 
        <tr key={key}>
            <td class="hover:bg-teal-200">{value.username}</td>
            <td class="hover:bg-teal-200">{value.email}</td>
        </tr>
    );

    return (
        <div className="mx-auto flex items-center max-w-2xl bg-cyan-100 p-1 rounded-xl">
            <table class="table w-full ...">
                <thead>
                    <tr>
                        <th class="hover:bg-teal-200">User</th>
                        <th class="hover:bg-teal-200">Email</th>
                    </tr>
                </thead>
                <tbody>
                    {listUsers}
                </tbody>
            </table>
        </div>
    );
}

export default App;
